import { useState, useEffect } from 'react';
import { getDashboard, getUsers, blockUser, getPendingProducts, approveProduct, getAllOrders, updateOrderStatus, getCoupons, createCoupon, toggleCoupon, deleteCoupon } from '../services/api';
import { toast } from 'react-toastify';

const AdminDashboard = () => {
  const [tab, setTab] = useState('dashboard');
  const [stats, setStats] = useState({});
  const [users, setUsers] = useState([]);
  const [pending, setPending] = useState([]);
  const [orders, setOrders] = useState([]);
  const [coupons, setCoupons] = useState([]);
  const [couponForm, setCouponForm] = useState({ code: '', discountType: 'percentage', discountValue: '', minOrderAmount: '', maxUses: '', expiresAt: '' });

  useEffect(() => {
    getDashboard().then(r => setStats(r.data));
  }, []);

  const loadUsers = async () => { const r = await getUsers(); setUsers(r.data); };
  const loadPending = async () => { const r = await getPendingProducts(); setPending(r.data); };
  const loadOrders = async () => { const r = await getAllOrders(); setOrders(r.data); };
  const loadCoupons = async () => { const r = await getCoupons(); setCoupons(r.data); };

  const handleTab = (t) => { setTab(t); if (t === 'users') loadUsers(); if (t === 'pending') loadPending(); if (t === 'orders') loadOrders(); if (t === 'coupons') loadCoupons(); };
  const handleBlock = async (id) => { await blockUser(id); loadUsers(); toast.success('Updated!'); };
  const handleApprove = async (id) => { await approveProduct(id); loadPending(); toast.success('Approved!'); };
  const handleToggleCoupon = async (id) => { await toggleCoupon(id); loadCoupons(); toast.success('Updated!'); };
  const handleDeleteCoupon = async (id) => { if (!window.confirm('Delete coupon?')) return; await deleteCoupon(id); loadCoupons(); toast.success('Deleted!'); };
  const handleCreateCoupon = async (e) => {
    e.preventDefault();
    try {
      await createCoupon({ ...couponForm, discountValue: Number(couponForm.discountValue), minOrderAmount: Number(couponForm.minOrderAmount) || 0, maxUses: couponForm.maxUses ? Number(couponForm.maxUses) : null, expiresAt: couponForm.expiresAt || undefined });
      setCouponForm({ code: '', discountType: 'percentage', discountValue: '', minOrderAmount: '', maxUses: '', expiresAt: '' });
      loadCoupons(); toast.success('Coupon created!');
    } catch (err) { toast.error(err.response?.data?.message || 'Error'); }
  };

  return (
    <div className="admin-page">
      <h1>Admin Dashboard</h1>
      <div className="admin-tabs">
        {['dashboard', 'users', 'pending', 'orders', 'coupons'].map(t => (
          <button key={t} className={tab === t ? 'active' : ''} onClick={() => handleTab(t)}>{t.charAt(0).toUpperCase() + t.slice(1)}</button>
        ))}
      </div>

      {tab === 'dashboard' && (
        <div className="stats-grid">
          <div className="stat-card"><h3>Total Users</h3><p>{stats.users}</p></div>
          <div className="stat-card"><h3>Total Products</h3><p>{stats.products}</p></div>
          <div className="stat-card"><h3>Total Orders</h3><p>{stats.orders}</p></div>
          <div className="stat-card"><h3>Revenue</h3><p>PKR {stats.revenue?.toLocaleString()}</p></div>
        </div>
      )}

      {tab === 'users' && (
        <table className="admin-table">
          <thead><tr><th>Name</th><th>Email</th><th>Role</th><th>Status</th><th>Action</th></tr></thead>
          <tbody>{users.map(u => (
            <tr key={u._id}>
              <td>{u.name}</td><td>{u.email}</td><td>{u.role}</td>
              <td><span className={u.isBlocked ? 'badge-red' : 'badge-green'}>{u.isBlocked ? 'Blocked' : 'Active'}</span></td>
              <td><button className="btn-sm" onClick={() => handleBlock(u._id)}>{u.isBlocked ? 'Unblock' : 'Block'}</button></td>
            </tr>
          ))}</tbody>
        </table>
      )}

      {tab === 'pending' && (
        <div className="pending-list">
          {pending.map(p => (
            <div key={p._id} className="pending-card">
              <div><h4>{p.name}</h4><p>By: {p.seller?.name}</p><p>PKR {p.price}</p></div>
              <button className="btn-primary btn-sm" onClick={() => handleApprove(p._id)}>Approve</button>
            </div>
          ))}
        </div>
      )}

      {tab === 'orders' && (
        <table className="admin-table">
          <thead><tr><th>ID</th><th>Customer</th><th>Total</th><th>Status</th><th>Action</th></tr></thead>
          <tbody>{orders.map(o => (
            <tr key={o._id}>
              <td>#{o._id.slice(-6)}</td><td>{o.user?.name}</td>
              <td>PKR {o.totalPrice?.toLocaleString()}</td><td>{o.status}</td>
              <td>
                <select defaultValue={o.status} onChange={async e => { await updateOrderStatus(o._id, { status: e.target.value }); toast.success('Status updated!'); }}>
                  {['pending','processing','shipped','delivered','cancelled'].map(s => <option key={s} value={s}>{s}</option>)}
                </select>
              </td>
            </tr>
          ))}</tbody>
        </table>
      )}

      {tab === 'coupons' && (
        <div className="coupons-section">
          <form className="coupon-form" onSubmit={handleCreateCoupon}>
            <h3>Create Coupon</h3>
            <div className="form-row">
              <input placeholder="Code (e.g. SAVE10)" value={couponForm.code} onChange={e => setCouponForm(p => ({ ...p, code: e.target.value.toUpperCase() }))} required />
              <select value={couponForm.discountType} onChange={e => setCouponForm(p => ({ ...p, discountType: e.target.value }))}>
                <option value="percentage">Percentage (%)</option>
                <option value="fixed">Fixed (PKR)</option>
              </select>
              <input type="number" placeholder="Discount value" value={couponForm.discountValue} onChange={e => setCouponForm(p => ({ ...p, discountValue: e.target.value }))} required />
              <input type="number" placeholder="Min order (PKR)" value={couponForm.minOrderAmount} onChange={e => setCouponForm(p => ({ ...p, minOrderAmount: e.target.value }))} />
              <input type="number" placeholder="Max uses (blank = unlimited)" value={couponForm.maxUses} onChange={e => setCouponForm(p => ({ ...p, maxUses: e.target.value }))} />
              <input type="date" placeholder="Expires at" value={couponForm.expiresAt} onChange={e => setCouponForm(p => ({ ...p, expiresAt: e.target.value }))} />
            </div>
            <button className="btn-primary btn-sm" type="submit">Create Coupon</button>
          </form>
          <table className="admin-table">
            <thead><tr><th>Code</th><th>Type</th><th>Value</th><th>Min Order</th><th>Used / Max</th><th>Expires</th><th>Status</th><th>Actions</th></tr></thead>
            <tbody>{coupons.map(c => (
              <tr key={c._id}>
                <td><strong>{c.code}</strong></td>
                <td>{c.discountType}</td>
                <td>{c.discountType === 'percentage' ? `${c.discountValue}%` : `PKR ${c.discountValue}`}</td>
                <td>{c.minOrderAmount ? `PKR ${c.minOrderAmount}` : '—'}</td>
                <td>{c.usedCount} / {c.maxUses ?? '∞'}</td>
                <td>{c.expiresAt ? new Date(c.expiresAt).toLocaleDateString() : '—'}</td>
                <td><span className={c.isActive ? 'badge-green' : 'badge-red'}>{c.isActive ? 'Active' : 'Inactive'}</span></td>
                <td>
                  <button className="btn-sm" onClick={() => handleToggleCoupon(c._id)}>{c.isActive ? 'Disable' : 'Enable'}</button>
                  <button className="btn-sm btn-danger" onClick={() => handleDeleteCoupon(c._id)}>Delete</button>
                </td>
              </tr>
            ))}</tbody>
          </table>
        </div>
      )}
    </div>
  );
};

export default AdminDashboard;
